export interface RankEntry {
  id: string;
  keyword: string;
  targetUrl: string;
  rank: number | 'N/A' | 'Checking...';
  status: 'pending' | 'processing' | 'completed' | 'error';
  timestamp?: string;
}

export interface CheckerStats {
  total: number;
  completed: number;
  top3: number;
  top10: number;
  outOfRank: number;
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const checkNaverRank = async (keyword: string, targetUrl: string): Promise<number | 'N/A'> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Naver search engine ranking check request.
      Keyword: "${keyword}"
      Target URL: "${targetUrl}"

      Task: Simulate or search for the current Naver search engine result page (SERP) for this keyword.
      Determine the organic rank (1-100) of the target URL. 
      If the URL is found in the top 100 results, return ONLY the rank number.
      If the URL is NOT found in the top 100, return 'N/A'.
      Ignore ad results. Only count organic results.`,
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    const result = response.text?.trim() || '';
    if (result.toUpperCase() === 'N/A') return 'N/A';

    const rank = parseInt(result.replace(/[^0-9]/g, ''), 10);
    return isNaN(rank) ? 'N/A' : rank;
  } catch (error) {
    console.error("Error checking rank:", error);
    throw error;
  }
};

import React, { useState } from 'react';

interface InputSectionProps {
  onStart: (keywords: string[], urls: string[]) => void;
  isProcessing: boolean;
}

export const InputSection: React.FC<InputSectionProps> = ({ onStart, isProcessing }) => {
