  const [urlInput, setUrlInput] = useState('');

  const handleProcess = () => {
    const keywords = keywordInput.split('\n').map(s => s.trim()).filter(s => s !== '');
    const urls = urlInput.split('\n').map(s => s.trim()).filter(s => s !== '');
    onStart(keywords, urls);
