        setResults(prev => prev.map((item, idx) => 
          // Fix: '미노출' is now a valid value for the rank property
          idx === i ? { ...item, rank: '미노출', status: 'error' } : item
        ));
      }

      setProgress(Math.round(((i + 1) / maxItems) * 100));
